package pages;import dict.Elements;import io.qameta.allure.Step;import static com.codeborne.selenide.Condition.visible;import static com.codeborne.selenide.Selectors.byText;import static com.codeborne.selenide.Selectors.shadowCss;import static com.codeborne.selenide.Selenide.$;import com.codeborne.selenide.Selenide;public class LoginPage extends BasePage {    private static final String LOGIN = "[name=email]";    private static final String PASSWORD = "[name=password]";    @Step("Opening login page")    public LoginPage open() {        Selenide.open("/login");        return this;    }    @Step("Login with user name '{}' and password '{}'")    public void login(String user, String password) {        $(shadowCss("#accept", "#usercentrics-cmp-ui")).click();        $(LOGIN).setValue(user);        $(PASSWORD).setValue(password);        $(byText(Elements.SIGN_IN)).click();    }    @Override    public LoginPage isPageOpened() {        $(byText(Elements.SIGN_IN)).shouldBe(visible);        return this;    }}